    def pad_sequence(seq, maxlen):
        # Truncate if longer than maxlen; otherwise pad with 0s.
        if len(seq) >= maxlen:
            return seq[:maxlen]
        else:
            return seq + [0] * (maxlen - len(seq))

    for key, seqs in data_list.items():
        # Processed sequences for the current key will be stored here.
        processed_seqs = []

