import numpy as np
from scipy.signal import argrelextrema

def idxsOfRelativeExtrema(x, maxima, allowEq, axis):
    # Convert input to numpy array
    arr = np.asarray(x)

    # Input validation
    if arr.size == 0:
        # Return an empty array if the input is empty
        return np.array([])
    if arr.size == 1:
        # If only one element, there is no relative extrema; return index 0.
        return np.array([0])

    # Set pad value: for maxima use -inf; for minima use +inf.
    pad = -np.inf if maxima else np.inf

    # Select comparison function based on maxima/minima and equality allowance.
    if maxima:
        cmp_fun = np.greater_equal if allowEq else np.greater
    else:
        cmp_fun = np.less_equal if allowEq else np.less

    # One-dimensional case
    if arr.ndim == 1:
        # Append pad at both ends to handle edge comparisons if needed.
        # Here, we can pad both ends so that the boundary points can be compared.
        padded = np.concatenate(([pad], arr, [pad]))
        # The extrema in the padded array are shifted by one.
        # We use order=1 to compare the immediate neighbors.
        idx_in_padded = argrelextrema(padded, cmp_fun, order=1)[0]
        # Filter out the indices corresponding to the actual array (i.e. skip the first and last padded entries).
        valid_idx = idx_in_padded[(idx_in_padded > 0) & (idx_in_padded < len(padded)-1)] - 1
        return valid_idx

    # Two-dimensional case
    if arr.ndim == 2:
        # The axis parameter determines whether we search on rows (axis=1) or columns (axis=0).
        # We'll pad along the specified axis with the pad value.
        if axis == 0:
            # Pad rows: add one row at top and bottom.
            pad_width = ((1, 1), (0, 0))
            padded = np.pad(arr, pad_width, mode='constant', constant_values=pad)
            # For each column, find indices where the value is an extrema along the column.
            result = []
            for j in range(padded.shape[1]):
                col = padded[:, j]
                idxs = argrelextrema(col, cmp_fun, order=1)[0]
                # Only include indices that correspond to valid original rows.
                for idx in idxs:
                    if 0 < idx < padded.shape[0]-1:
                        result.append((idx - 1, j))
            return np.array(result)
        elif axis == 1:
            # Pad columns: add one column at beginning and end.
            pad_width = ((0, 0), (1, 1))
            padded = np.pad(arr, pad_width, mode='constant', constant_values=pad)
            result = []
            for i in range(padded.shape[0]):
                row = padded[i, :]
                idxs = argrelextrema(row, cmp_fun, order=1)[0]
                for idx in idxs:
                    if 0 < idx < padded.shape[1]-1:
                        result.append((i, idx - 1))
            return np.array(result)
        else:
            raise ValueError("Axis must be 0 (columns) or 1 (rows)")

    raise ValueError("Only 1D or 2D arrays are supported.")

# For example, the following call:
if __name__ == "__main__":
    x = [1, 3, 2, 5, 4]
    result = idxsOfRelativeExtrema(x, maxima=True, allowEq=False, axis=0)
    print(result)  # Expected output: array([1, 3])
