import numpy as np

def sp1(data, maxvalue, issuccessful):
    # Check if data is of type list, tuple, or numpy.ndarray
    if not isinstance(data, (list, tuple, np.ndarray)):
        return (np.nan, np.nan, np.nan)

    # If issuccessful is provided, validate its type and its length matches data length.
    if issuccessful is not None:
        if not isinstance(issuccessful, (list, tuple, np.ndarray)):
            return (np.nan, np.nan, np.nan)
        if len(issuccessful) != len(data):
            return (np.nan, np.nan, np.nan)

    # Cleaning data: filter out NaN values. Also adjust issuccessful accordingly.
    dat = []
    success_flags = []
    for i, val in enumerate(data):
        if not np.isnan(val):
            dat.append(val)
            if issuccessful is not None:
                success_flags.append(issuccessful[i])

    # If cleaned data is empty, return tuple of three np.nan values.
    if len(dat) == 0:
        return (np.nan, np.nan, np.nan)

    # Further filtering based on success:
    # If issuccessful is provided, filter dat by corresponding True values.
    if issuccessful is not None:
        # For the valid data points (non-NaNs), pick those that are True
        successful_data = [d for d, flag in zip(dat, success_flags) if flag]
    else:
        # If issuccessful is not provided, success is defined as values less than maxvalue.
        successful_data = [d for d in dat if d < maxvalue]

    # Calculate success ratio: number of successful entries divided by total valid entries.
    N = len(dat)
    count_success = len(successful_data)
    succ_ratio = count_success / N

    # If success ratio is zero, then return (np.inf, 0.0, 0)
    if succ_ratio == 0:
        return (np.inf, 0.0, 0)

    # Compute mean of the successful data, then adjust by success ratio.
    mean_success = np.mean(successful_data)
    adjusted_mean = mean_success / succ_ratio

    # Return adjusted mean, success ratio, and count of successful entries.
    return (adjusted_mean, succ_ratio, count_success)

# Example usage:
if __name__ == "__main__":
    # Provided test
    data = [3.5, 7.2, np.nan, -2.1, 5.0]
    maxvalue = 10.0
    issuccessful = [True, False, None, True, True]
    result = sp1(data, maxvalue, issuccessful)
    print(result)  # Expected output: (2.8444444444444446, 0.75, 3)
