import numpy as np
from collections.abc import Iterable

def sp(data, maxvalue, issuccessful, allowinf):
    # Check if data is iterable
    if not isinstance(data, Iterable):
        return (np.nan, np.nan, np.nan)

    # Convert data to list (if not already) for consistent indexing
    data_list = list(data)

    # Validate issuccessful if provided: must be iterable and same length as data_list.
    if issuccessful is not None:
        if not isinstance(issuccessful, Iterable) or len(issuccessful) != len(data_list):
            issuccessful = None
        else:
            issuccessful = list(issuccessful)

    # Clean data: filter out NaN values and (if available) pair them with issuccessful 
    paired = []
    simple_data = []
    for idx, val in enumerate(data_list):
        # Check if val is np.nan; note that np.nan != np.nan, so use np.isnan
        if isinstance(val, float) and np.isnan(val):
            continue
        # For non-float types, try converting to float, but assume valid if not nan.
        simple_data.append(val)
        if issuccessful is not None:
            paired.append((val, issuccessful[idx]))

    # After filtering, get number of valid entries.
    N = len(simple_data)
    if N == 0:
        return (np.nan, np.nan, np.nan)

    # Sort the valid data. If issuccessful is valid, sort the pairs together.
    if issuccessful is not None:
        paired_sorted = sorted(paired, key=lambda x: x[0])
        dat = [val for val, flag in paired_sorted]
        # Filter successful data: values whose corresponding flag is True.
        succdat = [val for val, flag in paired_sorted if flag]
    else:
        dat = sorted(simple_data)
        # When issuccessful is None, success condition: the value is less than maxvalue.
        succdat = [val for val in dat if val < maxvalue]

    # Calculate success rate: ratio of count of succdat to total valid entries.
    succ_rate = len(succdat) / N

    # Compute result res.
    if len(succdat) == 0:
        # If no successful entries found, check allowinf.
        if allowinf:
            res = float('inf')
        else:
            res = sum(dat)
    else:
        # If there are successful entries, compute res as: 
        # (average of dat) divided by (length of succdat divided by 1) which simplifies to sum(dat)/len(succdat)
        res = sum(dat) / len(succdat)

    return (res, succ_rate, len(succdat))


# Testing the function with the provided input
if __name__ == "__main__":
    data = [12.5, np.nan, 45.3, 78.1, np.nan, -20.0]
    maxvalue = 50.0
    issuccessful = [True, False, True, True, False, True]
    allowinf = False

    result = sp(data, maxvalue, issuccessful, allowinf)
    print(result)  # Expected (28.974999999999998, 1.0, 4)
