import numpy as np

def process_shape_padding(tshape, pad, margin):
    # Helper function to ensure the input is a tuple of length 2
    def to_tuple(x):
        if isinstance(x, int):
            return (int(x), int(x))
        try:
            # Ensure we have two elements, convert each element to int
            x = tuple(x)
        except TypeError:
            raise ValueError("Input must be an integer or a tuple of integers.")
        if len(x) != 2:
            raise ValueError("Input tuple must have exactly two elements.")
        return tuple(map(int, x))

    tshape = to_tuple(tshape)
    pad = to_tuple(pad)
    margin = to_tuple(margin)

    # Double the padding values to account for both sides
    oly = pad[0] * 2
    olx = pad[1] * 2

    # Calculate weights for the height (wy) and width (wx) dimensions.
    # We create an array from 1 to oly (or olx) and normalize by dividing by oly + 1 (or olx + 1).
    wy = np.arange(1, oly + 1) / (oly + 1) if oly > 0 else np.array([])
    wx = np.arange(1, olx + 1) / (olx + 1) if olx > 0 else np.array([])

    return {
        'tshape': tshape,
        'pad': pad,
        'margin': margin,
        'wy': wy,
        'wx': wx
    }
