import numpy as np
import pandas as pd

def to_dataframe(ifp: dict, interactions: list, count: bool, dtype: type, drop_empty: bool, index_col: str) -> pd.DataFrame:
    # Set default dtype and empty_value if needed.
    if dtype is None:
        dtype = np.uint8 if count else bool
    empty_value = 0 if count else False

    # Collect unique residue pairs from all frames.
    unique_pairs = set()
    for frame_dict in ifp.values():
        for pair in frame_dict.keys():
            unique_pairs.add(pair)
    # Sort residue pairs (by ligand then protein).
    unique_pairs = sorted(unique_pairs, key=lambda x: (x[0], x[1]))

    # Create a list of column labels for each residue pair and for each desired interaction.
    # Each column label is a tuple: (ligand, protein, interaction)
    columns = []
    for pair in unique_pairs:
        for inter in interactions:
            columns.append((pair[0], pair[1], inter))

    # Build the data, iterating frames in sorted order.
    index = sorted(ifp.keys())
    data_list = []
    for frame in index:
        frame_data = []
        frame_dict = ifp.get(frame, {})
        for pair in unique_pairs:
            pair_dict = frame_dict.get(pair, {})
            for inter in interactions:
                # If the interaction exists and has a non-empty tuple of values:
                if inter in pair_dict and pair_dict[inter]:
                    value = len(pair_dict[inter]) if count else True
                else:
                    value = empty_value
                frame_data.append(value)
        data_list.append(frame_data)

    # Convert the list of lists into a 2D numpy array with the specified dtype.
    values = np.array(data_list, dtype=dtype)

    # Create a MultiIndex for DataFrame columns.
    col_index = pd.MultiIndex.from_tuples(columns, names=["ligand", "protein", "interaction"])

    # Construct the DataFrame.
    df = pd.DataFrame(values, columns=col_index, index=index)
    df.index.name = index_col

    # Optionally drop columns that contain only the empty_value.
    if drop_empty:
        cols_to_drop = [col for col in df.columns if (df[col] == empty_value).all()]
        df.drop(columns=cols_to_drop, inplace=True)

    return df

# Example usage:
if __name__ == "__main__":
    ifp = {
        0: {
            ('lig_0', 'prot_0'): {'int_0': (1, 2), 'int_1': (3,)},
            ('lig_1', 'prot_1'): {'int_0': (4,)}
        },
        1: {
            ('lig_0', 'prot_0'): {'int_1': (5, 6)},
            ('lig_1', 'prot_1'): {}
        }
    }
    interactions = ['int_0', 'int_1']
    count = False
    dtype = bool
    drop_empty = True
    index_col = "Frame_Index"

    df = to_dataframe(ifp, interactions, count, dtype, drop_empty, index_col)
    print(df)
