import numpy as np

def process_parameters_psd(dim, mean, cov):
    # 1. Dimension Initialization
    if dim is None:
        dim = 1

    # 2. Mean Processing
    if mean is not None:
        mean = np.array(mean, dtype=float)
        dim = mean.shape[0]
    elif cov is not None:
        cov_arr = np.array(cov, dtype=float)
        # If covariance is 1D, interpret as diagonal and set dimension to length 1 if one element, else use its length
        if cov_arr.ndim == 1:
            dim = cov_arr.shape[0] if cov_arr.shape[0] > 1 else 1
        elif cov_arr.ndim == 2:
            # if rows and columns match, use the number of rows; otherwise, set dim to 1 (fallback)
            if cov_arr.shape[0] == cov_arr.shape[1]:
                dim = cov_arr.shape[0]
            else:
                dim = 1

    # 3. Default Mean and Covariance Initialization
    if mean is None:
        mean = np.zeros(dim, dtype=float)
    if cov is None:
        cov = 1.0

    # Convert cov to numpy array
    cov = np.array(cov, dtype=float)

    # 4. Reshaping for Single Dimension
    # Ensure mean is 1D
    if dim == 1:
        mean = np.atleast_1d(mean)

    # Process the covariance matrix based on its dimensionality
    if cov.ndim == 0:
        # Scalar: multiply by the identity matrix
        cov = cov * np.eye(dim)
    elif cov.ndim == 1:
        # 1D array: convert to diagonal matrix
        cov = np.diag(cov)
    elif cov.ndim == 2:
        # If already a 2D array, check if its shape matches (dim, dim)
        if cov.shape != (dim, dim):
            # If not matching and not square, set to identity matrix.
            if cov.shape[0] != cov.shape[1]:
                cov = np.eye(dim)
            else:
                # If square but wrong dimension, set to zero matrix.
                cov = np.zeros((dim, dim))
    else:
        # If cov has more than 2 dimensions, set to identity matrix.
        cov = np.eye(dim)

    return dim, mean, cov

# Example usage:
if __name__ == '__main__':
    dim = 2
    mean = [1.5, -0.5]
    cov = [[1.0, 0.5], [0.5, 2.0]]
    processed_dim, processed_mean, processed_cov = process_parameters_psd(dim, mean, cov)
    print((processed_dim, processed_mean, processed_cov))
