import pandas as pd

def unmelt(df: pd.DataFrame) -> pd.DataFrame:
    # Step 2: Check if input is a DataFrame; if not, return it as-is.
    if not isinstance(df, pd.DataFrame):
        return df

    # Determine whether the DataFrame has a MultiIndex.
    is_multi_index = isinstance(df.index, pd.MultiIndex)
    if is_multi_index:
        # For MultiIndex, get unique names from the first index level.
        names = df.index.get_level_values(0).unique()
    else:
        names = df.index

    # Step 4: Check if the DataFrame has a single column named 'Value'.
    single_value_col = (len(df.columns) == 1 and df.columns[0] == 'Value')

    # When the DataFrame has a single 'Value' column
    if single_value_col:
        if not is_multi_index:
            # For a single-level index,
            # stack the DataFrame to gather the single-value column into a Series,
            # drop any NaNs, convert to a one-row DataFrame and then transpose to get metrics as columns.
            stacked = df.stack().dropna()
            result = stacked.to_frame().T
        else:
            # For a MultiIndex:
            # For each unique value (from the first level of the index),
            # slice the DataFrame and then concatenate these slices along columns.
            slices = []
            for name in names:
                try:
                    slice_df = df.xs(name, level=0)
                    slices.append(slice_df)
                except KeyError:
                    continue
            result = pd.concat(slices, axis=1, keys=names)
        # Step 7: If the result has a MultiIndex for columns, drop the second level.
        if isinstance(result.columns, pd.MultiIndex) and result.columns.nlevels > 1:
            result.columns = result.columns.get_level_values(0)
        return result
    else:
        # When the DataFrame doesn't meet the single 'Value' column condition,
        # perform a similar transformation without dropping the second column level.
        if not is_multi_index:
            stacked = df.stack().dropna()
            result = stacked.to_frame().T
        else:
            slices = []
            for name in names:
                try:
                    slice_df = df.xs(name, level=0)
                    slices.append(slice_df)
                except KeyError:
                    continue
            result = pd.concat(slices, axis=1, keys=names)
        return result
