import numpy as np
import pandas as pd

def reduce_mem_usage(df):
    start_mem_usg = df.memory_usage().sum() / 1024**2
    NAlist = []

    for col in df.columns:
        # Process only numeric columns (skip objects)
        if df[col].dtype != object:
            # Replace NaN and infinite values if found.
            if df[col].isnull().any() or (np.isinf(df[col]).any()):
                finite_mask = np.isfinite(df[col])
                if finite_mask.any():
                    replace_val = df[col][finite_mask].min()
                else:
                    replace_val = 0
                df[col].replace([np.nan, np.inf, -np.inf], replace_val, inplace=True)
                # Track columns that had non-finite values
                if col not in NAlist:
                    NAlist.append(col)

            # Attempt converting to integer if the values are effectively integers.
            as_int = df[col].round().astype(np.int64)
            diff = np.sum(np.abs(df[col] - as_int))
            if diff < 0.01:
                c_min = df[col].min()
                c_max = df[col].max()
                # for non-negative integers, opt for unsigned types when possible.
                if c_min >= 0:
                    if c_max < np.iinfo(np.uint8).max:
                        df[col] = df[col].astype(np.uint8)
                    elif c_max < np.iinfo(np.uint16).max:
                        df[col] = df[col].astype(np.uint16)
                    elif c_max < np.iinfo(np.uint32).max:
                        df[col] = df[col].astype(np.uint32)
                    else:
                        df[col] = df[col].astype(np.uint64)
                else:
                    # for signed integers, choose smallest possible type.
                    if c_min > np.iinfo(np.int8).min and c_max < np.iinfo(np.int8).max:
                        df[col] = df[col].astype(np.int8)
                    elif c_min > np.iinfo(np.int16).min and c_max < np.iinfo(np.int16).max:
                        df[col] = df[col].astype(np.int16)
                    elif c_min > np.iinfo(np.int32).min and c_max < np.iinfo(np.int32).max:
                        df[col] = df[col].astype(np.int32)
                    else:
                        df[col] = df[col].astype(np.int64)
            else:
                # If the column cannot be safely cast to integer, use float32.
                df[col] = df[col].astype(np.float32)

    end_mem_usg = df.memory_usage().sum() / 1024**2
    mem_usg_reduction = 100 * (start_mem_usg - end_mem_usg) / start_mem_usg
    return df, NAlist, mem_usg_reduction

# Example usage:
if __name__ == "__main__":
    data = {
        'col_0': [1, 2, 3, 4, 5],
        'col_1': [1.1, 2.2, 3.3, np.nan, 5.5],
        'col_2': [np.nan, np.inf, -np.inf, 4, 5],
        'col_3': [100000, 200000, 300000, 400000, 500000]
    }

    df = pd.DataFrame(data)
    df_reduced, na_list, mem_usg_percentage = reduce_mem_usage(df)

    print("Optimized DataFrame:")
    print(df_reduced)
    print("\nColumns with NaN or infinite values replaced:", na_list)
    print("\nMemory usage reduction (%):", mem_usg_percentage)
