        # Check whether the hex_color string has exactly 6 characters
        if isinstance(hex_color, str) and len(hex_color) == 6:
            try:
                return (int(hex_color[0:2], 16), int(hex_color[2:4], 16), int(hex_color[4:6], 16))
            except ValueError:
                return (pd.NA, pd.NA, pd.NA)
        return (pd.NA, pd.NA, pd.NA)

    # Apply the conversion to the 'color' column and store the results in new columns 'R', 'G', 'B'
    rgb_values = filtered_df['color'].apply(hex_to_rgb)
    filtered_df['R'] = rgb_values.apply(lambda x: x[0])
    filtered_df['G'] = rgb_values.apply(lambda x: x[1])
    filtered_df['B'] = rgb_values.apply(lambda x: x[2])

    # Initialize the workspace with the header
    ws = [header]

    # Iterate over each row with itertuples for efficient row access
    for row in filtered_df.itertuples(index=False):
