import numpy as np
from scipy import stats

def preprocess_data(data):
    # Convert each element to float and filter out NaN values
    cleaned = []
    for item in data:
        try:
            num = float(item)
            if np.isnan(num):
                continue
            cleaned.append(num)
        except Exception:
            continue
    # If there is more than one element, remove outliers beyond 3 standard deviations
    if len(cleaned) > 1:
        mean_val = np.mean(cleaned)
        std_val = np.std(cleaned)
        lower_bound = mean_val - 3 * std_val
        upper_bound = mean_val + 3 * std_val
        cleaned = [x for x in cleaned if lower_bound <= x <= upper_bound]
    return cleaned

def interpret_result(statistic, p_value, alpha):
    if p_value < alpha:
        return f"Significant difference between distributions (p={p_value:.5f}, KS stat={statistic:.5f})"
    else:
        return f"No significant difference between distributions (p={p_value:.5f}, KS stat={statistic:.5f})"

def test_nametuples_agree(data1, data2):
    alpha = 0.05
    processed1 = preprocess_data(data1)
    processed2 = preprocess_data(data2)
    # Check for sufficient data after preprocessing
    if len(processed1) < 2 or len(processed2) < 2:
        return "Insufficient data after preprocessing."
    # Perform a two-sample Kolmogorov-Smirnov test to compare the two datasets
    test_result = stats.ks_2samp(processed1, processed2)
    return interpret_result(test_result.statistic, test_result.pvalue, alpha)

if __name__ == "__main__":
    import numpy as np
    data1 = [1.2, 2.3, 3.1, np.nan, 4.5, 5.0, np.nan, 6.7]
    data2 = [1.0, 2.1, 3.5, 4.0, np.nan, 5.2, 6.0, 7.1]
    print(test_nametuples_agree(data1, data2))
