import numpy as np
import numpy.ma as ma
from scipy.stats import mstats

def compute_ranking(data, mask_indices, axis, use_missing):
    # Convert input data to an at least 1D masked array
    x = ma.array(np.atleast_1d(data))

    # Apply masking for provided indices
    if mask_indices:
        for idx in mask_indices:
            # Mask the specified element; indexing errors are ignored
            try:
                x[idx] = ma.masked
            except Exception:
                pass

    # If the array is empty, return an empty numpy array
    if x.size == 0:
        return np.array([])

    # If all elements are masked, return an array filled with np.nan
    if x.count() == 0:
        return np.full(x.shape, np.nan)

    # For one-dimensional arrays, ensure ranking is computed along axis 0
    if x.ndim == 1:
        axis = 0

    try:
        # Use mstats.rankdata to compute the ranking along the specified axis.
        # The use_missing flag indicates how to handle missing values.
        ranked = mstats.rankdata(x, axis=axis, use_missing=use_missing)
    except TypeError:
        return np.full(x.shape, np.nan)

    # If the result is a masked array, fill masked entries with np.nan
    if isinstance(ranked, ma.MaskedArray):
        ranked = ranked.filled(np.nan)
    return ranked

# Sample usage
if __name__ == '__main__':
    data = np.array([[10, 20, 30], [40, 50, 60]])
    mask_indices = [(0, 1), (1, 2)]  # Masking elements 20 and 60
    axis = 1
    use_missing = True
    print(compute_ranking(data, mask_indices, axis, use_missing))
