import numpy as np
from scipy import sparse

def make_system(A, x, b, formats=None):
    # If formats is given, check/convert the matrix A to a proper sparse format if needed.
    if formats is not None and len(formats) > 0:
        # If A is already a sparse matrix:
        if sparse.isspmatrix(A):
            current_format = A.getformat()
            # If 'csr' is requested and A is not CSR, handle conversion
            if 'csr' in formats and current_format != 'csr':
                if current_format == 'bsr':
                    A = A.tocsr()
                else:
                    A = sparse.csr_matrix(A)
            elif current_format not in formats:
                # Convert to the first desired format from the formats list.
                desired = formats[0]
                if desired == 'csr':
                    A = A.tocsr()
                elif desired == 'bsr':
                    A = A.tobsr()
                elif desired == 'csc':
                    A = A.tocsc()
                else:
                    # Fallback to csr conversion if format is not recognized.
                    A = sparse.csr_matrix(A)
        else:
            # A is a dense matrix; if a sparse format is specified, convert it.
            desired = formats[0]
            if desired == 'csr':
                A = sparse.csr_matrix(A)
            elif desired == 'bsr':
                A = sparse.bsr_matrix(A)
            elif desired == 'csc':
                A = sparse.csc_matrix(A)
            else:
                A = sparse.csr_matrix(A)
    else:
        # If formats not specified, but A might be dense or sparse, leave it as is.
        pass

    # Convert x and b to numpy arrays.
    x = np.asarray(x)
    b = np.asarray(b)

    # Get shape of A.
    # For both dense and sparse matrices, A.shape returns (M, N).
    M, N = A.shape

    # If A is not square, replace A with an identity matrix of size M in CSR format.
    if M != N:
        A = sparse.identity(M, format='csr', dtype=A.dtype if hasattr(A, 'dtype') else np.float64)

    # Reshape x: If x is (M,) or (M, 1), use it; otherwise, initialize x as zeros.
    if x.ndim == 1 and x.shape[0] == M:
        x = x.copy()
    elif x.ndim == 2 and x.shape == (M, 1):
        x = x.ravel()
    else:
        x = np.zeros(M)

    # Reshape b: If b is (M,) or (M, 1), use it; otherwise, initialize b as ones.
    if b.ndim == 1 and b.shape[0] == M:
        b = b.copy()
    elif b.ndim == 2 and b.shape == (M, 1):
        b = b.ravel()
    else:
        b = np.ones(M)

    # Data type consistency: if dtypes don't match, use np.float64.
    A_dtype = A.dtype if hasattr(A, 'dtype') else None
    x_dtype = x.dtype
    b_dtype = b.dtype
    # Check match: if any of them is None or they don't all equal, then reset to np.float64.
    if A_dtype is None or A_dtype != x_dtype or A_dtype != b_dtype:
        new_dtype = np.float64
        # If A is sparse, use .astype(new_dtype)
        if sparse.isspmatrix(A):
            A = A.astype(new_dtype)
        else:
            A = np.array(A, dtype=new_dtype)
        x = x.astype(new_dtype)
        b = b.astype(new_dtype)

    return A, x, b

# Example usage:
if __name__ == '__main__':
    # Create a sparse matrix in COO format.
    A = sparse.coo_matrix([[1, 0, 0], [0, 2, 0], [0, 0, 3]])
    x = np.array([[1], [2], [3]])
    b = np.array([[1], [1], [1]])
    formats = ['csr']

    A_processed, x_processed, b_processed = make_system(A, x, b, formats)

    # Print the results
    print(A_processed)
    print(x_processed)
    print(b_processed)
