def check_shape_loc_scale(distribution, params):
    # Unpack parameters assuming format (shape, loc, scale)
    shape, loc, scale = params
    # Check for NaN or inf in any value; if shape is iterable, check all of them.
    def is_bad(v):
        return np.isnan(v) or np.isinf(v)

    if isinstance(shape, (tuple, list, np.ndarray)):
        for s in shape:
            if is_bad(s):
                return False
    else:
        if is_bad(shape):
            return False
    if is_bad(loc) or is_bad(scale):
        return False

    # Distribution-specific checks: use distribution.name attribute.
    name = distribution.name if hasattr(distribution, 'name') else ''
    # Normal distribution: scale must be positive.
    if name == 'norm':
        if scale <= 0:
            return False
    # For "weibull_min", "gamma", and "rice": shape > 0 and scale > 0.
    elif name in ['weibull_min', 'gamma', 'rice']:
        if isinstance(shape, (tuple, list, np.ndarray)):
            # For gamma and such, we expect only one shape parameter.
            if any(s <= 0 for s in shape):
                return False
        else:
            if shape <= 0:
                return False
        if scale <= 0:
            return False
    # For beta: the shape parameter(s) must be > 0 and < 1e10.
    elif name == 'beta':
        # If shape is iterable, check each; otherwise check the single value.
        if isinstance(shape, (tuple, list, np.ndarray)):
            for s in shape:
                if s <= 0 or s >= 1e10:
                    return False
        else:
            if shape <= 0 or shape >= 1e10:
                return False
        # Also require scale > 0 for the beta distribution, and loc is finite.
        if scale <= 0:
            return False
    # Other distributions can be assumed valid if no obvious issues.
    return True

def fit(spsdotwhat, x, fwords):
    # Convert x to a numpy array and check if there are at least two unique values.
    x = np.asarray(x)
    if len(np.unique(x)) < 2:
        return None

    # Check if distribution has 'fit' method.
    if not hasattr(spsdotwhat, 'fit'):
        return None

    # Attempt to fit using the distribution's fit method.
    try:
        shape_loc_scale = spsdotwhat.fit(x, **fwords)
        # Ensure we return a tuple of three parameters.
        if not isinstance(shape_loc_scale, tuple) or len(shape_loc_scale) < 3:
            shape_loc_scale = (np.nan, np.nan, np.nan)
        else:
            # In case there are extra parameters, take the first three.
            shape_loc_scale = shape_loc_scale[:3]
    except Exception:
        shape_loc_scale = (np.nan, np.nan, np.nan)

    # Validate the fitted parameters.
    if not check_shape_loc_scale(spsdotwhat, shape_loc_scale):
        # For specific distributions try alternative (manual) fitting.
        name = spsdotwhat.name if hasattr(spsdotwhat, 'name') else ''
        if name == 'gamma':
            # Alternative fitting for gamma using method of moments.
            xm = np.mean(x)
            xv = np.var(x, ddof=1)
            if xv <= 0 or xm <= 0:
                return None
            # Derive shape and scale.
            a = xm**2 / xv
            scale = xv / xm
            loc = 0  # assume loc at 0 by default
            shape_loc_scale = (a, loc, scale)
        elif name == 'beta':
            # Alternative fitting for beta: need to normalize x to [0,1]
            xmin = np.min(x)
            xmax = np.max(x)
            if xmax == xmin:
                return None
            x_norm = (x - xmin) / (xmax - xmin)
            m = np.mean(x_norm)
            v = np.var(x_norm, ddof=1)
            if v <= 0 or m*(1-m) <= v:
                return None
            common = m*(1-m) / v - 1
            p = m * common
            q = (1-m) * common
            loc = xmin
            scale = xmax - xmin
            # For beta, we use a tuple for the shape parameters.
            shape_loc_scale = ((p, q), loc, scale)
        # Validate again after alternative fitting.
        if not check_shape_loc_scale(spsdotwhat, shape_loc_scale):
            return None

    # Perform Kolmogorov-Smirnov goodness-of-fit test.
    # Unpack parameters.
    shape, loc, scale = shape_loc_scale
    # Prepare the shape parameters for the distribution's cdf.
    if isinstance(shape, (tuple, list, np.ndarray)):
        shape_params = tuple(shape)
    else:
        shape_params = (shape,)
    try:
        # Define the CDF function using the fitted parameters.
        cdf_func = lambda v: spsdotwhat.cdf(v, *shape_params, loc=loc, scale=scale)
        ks_stat, _ = sps.kstest(x, cdf_func)
    except Exception:
        return None

    # If KS statistic indicates a poor fit (greater than 0.5), return None.
    if ks_stat > 0.5:
        return None

    return shape_loc_scale

# Example usage:
if __name__ == "__main__":
    # Example input
    x = np.array([1.2, 2.3, 2.1, 3.5, 2.8, 1.9, 2.4, 3.1, 2.7, 3.0])
    fwords = {}
    # Using gamma distribution as in the example.
    result = fit(sps.gamma, x, fwords)
    print(result)
