from scipy import stats
from scipy.stats import rv_continuous

# Predefined list of popular distribution names.
# For this example, we assume that 'k' is a special key to include the provided k_distribution,
# and 'norm' is another popular distribution.
popular_names = ['k', 'norm']

def get_distributions(distr, k_distribution):
    out_distr = []

    # Case 1: distr is a list.
    if isinstance(distr, list):
        for d in distr:
            if d == 'k':
                out_distr.append(k_distribution)
            else:
                if hasattr(stats, d):
                    dist_obj = getattr(stats, d)
                    try:
                        # Calling the distribution to get a frozen instance.
                        out_distr.append(dist_obj())
                    except Exception:
                        pass

    # Case 2: distr is a string.
    elif isinstance(distr, str):
        # If distr is 'full', include all continuous distributions from scipy.stats.
        if distr == 'full':
            for name in dir(stats):
                if not name.startswith('_'):
                    attr = getattr(stats, name)
                    if isinstance(attr, rv_continuous):
                        try:
                            out_distr.append(attr())
                        except Exception:
                            pass
        # If distr is 'popular', include distributions from the predefined popular_names list.
        elif distr == 'popular':
            for name in popular_names:
                if name == 'k':
                    out_distr.append(k_distribution)
                else:
                    if hasattr(stats, name):
                        dist_obj = getattr(stats, name)
                        try:
                            out_distr.append(dist_obj())
                        except Exception:
                            pass
        # Otherwise, treat distr as a single distribution name.
        else:
            if distr == 'k':
                out_distr.append(k_distribution)
            else:
                if hasattr(stats, distr):
                    dist_obj = getattr(stats, distr)
                    try:
                        out_distr.append(dist_obj())
                    except Exception:
                        pass

    # Return the list of distribution objects (or an empty list if none were found)
    return out_distr
