import tensorflow as tf

def tf_regularization_loss(bias, l2_regularization, filters, nonlinearity, l1_regularization):
    losses = []

    # L2 regularization
    if l2_regularization > 0.0:
        l2_filters = l2_regularization * tf.nn.l2_loss(filters)
        losses.append(l2_filters)
        if bias is not None:
            l2_bias = l2_regularization * tf.nn.l2_loss(bias)
            losses.append(l2_bias)

    # L1 regularization
    if l1_regularization > 0.0:
        l1_filters = l1_regularization * tf.reduce_sum(tf.abs(filters))
        losses.append(l1_filters)
        if bias is not None:
            l1_bias = l1_regularization * tf.reduce_sum(tf.abs(bias))
            losses.append(l1_bias)

    # Additional regularization from nonlinearity
    extra_loss = nonlinearity.regularization_loss()
    if extra_loss is not None:
        losses.append(extra_loss)

    if losses:
        total_loss = tf.add_n(losses)
    else:
        total_loss = 0
    return total_loss

# Example usage
