import tensorflow as tf

def precision(y_true, y_pred):
    true_positives = tf.reduce_sum(tf.keras.backend.clip(y_true * y_pred, 0, 1))
    predicted_positives = tf.reduce_sum(tf.keras.backend.clip(y_pred, 0, 1))
    return true_positives / (predicted_positives + tf.keras.backend.epsilon())

def recall(y_true, y_pred):
    true_positives = tf.reduce_sum(tf.keras.backend.clip(y_true * y_pred, 0, 1))
    possible_positives = tf.reduce_sum(tf.keras.backend.clip(y_true, 0, 1))
    return true_positives / (possible_positives + tf.keras.backend.epsilon())

def f1(y_true, y_pred):
    p = precision(y_true, y_pred)
    r = recall(y_true, y_pred)
    return 2 * (p * r) / (p + r + tf.keras.backend.epsilon())

# Example usage:
if __name__ == "__main__":
    y_true = tf.convert_to_tensor([[1, 0, 1], [0, 1, 0]], dtype=tf.float32)
    y_pred = tf.convert_to_tensor([[1, 0, 0], [0, 1, 1]], dtype=tf.float32)
    f1_score = f1(y_true, y_pred)
    tf.print("F1 Score:", f1_score)
