import pandas as pd
import lightgbm as lgb

def detect_categorical_columns(X):
    # Identify columns with object or category type as categorical
    return [col for col in X.columns if X[col].dtype == 'object' or str(X[col].dtype).startswith('category')]

def prediction(X, y, X_test, params, cat_cols_actual=None, cat_cols_to_store=None):
    num_boost_round = 10

    # Detect categorical columns if they are not provided
    if cat_cols_actual is None:
        cat_cols_actual = detect_categorical_columns(X)
    if cat_cols_to_store is None:
        cat_cols_to_store = cat_cols_actual.copy()

    # Convert categorical columns in both training and test data to type 'category'
    for col in cat_cols_actual:
        if col in X.columns:
            X[col] = X[col].astype('category')
    for col in cat_cols_to_store:
        if col in X_test.columns:
            X_test[col] = X_test[col].astype('category')

    # Extract unique sorted categorical values for the specified columns
    categorical_values = [sorted(X[col].dropna().unique().tolist()) for col in cat_cols_to_store]

    # Prepare LightGBM dataset
    train_data = lgb.Dataset(X, label=y, categorical_feature=cat_cols_to_store)

    # Train LightGBM model
    model = lgb.train(params, train_data, num_boost_round=num_boost_round)

    # Make predictions on the test dataset
    pred = model.predict(X_test)

    return {
        'pred': pred,
        'categorical_values': categorical_values
    }
